use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  bonus_percent:     Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator pays discounted debt: debt * (100 - bonus_percent) / 100
fn discounted_debt(debt: Int, bonus_percent: Int) -> Int {
  debt * (100 - bonus_percent) / 100
}

fn liquidator_pays_discounted(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt:          Int,
  bonus_percent: Int,
) -> Bool {
  let required = discounted_debt(debt, bonus_percent)
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= required
}

validator cdp_liquidation_bonus {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liquidation_ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_discounted_debt_zero_bonus(debt via fuzz.int_at_least(1)) {
  discounted_debt(debt, 0) == debt
}

test prop_discounted_debt_less_than_full(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(1, 50)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) < debt
}

test prop_discounted_debt_non_negative(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) >= 0
}

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  is_undercollateralized(debt * 119, debt * 100, 120)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// A position with zero debt is never undercollateralized regardless of collateral
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 300)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// A well-collateralized position (collateral*100 >= debt*ratio) must NOT be flagged
// collateral = debt * ratio, so collateral*100 == debt*ratio*100 >= debt*ratio for ratio>=1
test prop_well_collateralized_not_liquidatable(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(1, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral * 100 = debt * ratio * 100 >= debt * ratio  → not undercollateralized
  expect is_undercollateralized(debt * ratio, debt, ratio)
}

// No outputs means liquidator paid nothing; required > 0 means check must fail
test prop_no_outputs_liquidator_pays_nothing() fail {
  expect liquidator_pays_discounted([], Output { address: address.from_verification_key(#"deadbeef"), value: assets.zero, datum: transaction.NoDatum, reference_script: None }, 1000, 10)
}

// When bonus_percent = 100 the discounted debt is 0, but here we confirm that
// a strictly-positive debt with bonus < 100 produces required > 0, so empty
// outputs always fails — captured by a range that keeps required >= 1.
test prop_positive_required_no_outputs_fails(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(0, 99)),
) fail {
  let (debt, bonus) = vals
  // discounted_debt(debt, bonus) >= 1 for debt>=100, bonus<=99
  expect liquidator_pays_discounted(
    [],
    Output {
      address: address.from_verification_key(#"cafe"),
      value: assets.zero,
      datum: transaction.NoDatum,
      reference_script: None,
    },
    debt,
    bonus,
  )
}
